class EnvRunner(ABC):
    def __init__(self,
                 dataloader_cfg,
                 ):
       self.dataloader = dataloader_cfg.build()  

    def sample(self) -> dict:
        pass 

    def resume(self):
        pass
    def save(self):
        pass
    @abstractmethod
    def generate(self) -> Trajectory:
        """
        核心方法：生成一条轨迹
        包含：取数据 -> 环境交互 -> judger -> filter -> 返回轨迹
        """
        pass

    @abstractmethod
    def generate_batch(self) -> list[Trajectory]:
        pass
class BaseRLTrainer:
    def __init__(
        self,
        config,
        replay_buffer,
        infer_engine_controller,
        training_controller,
        env_runners: list[EnvRunner], 
    ):
        self.config = config
        self.infer_engine_controller = infer_engine_controller
        self.training_controller = training_controller
        self.replay_buffer = replay_buffer
        self.env_runners = env_runners

    def sync_weights(self):
        pass

    def save_ckpt(self):
        pass
    @abstractmethod
    def train_step(self):
        pass
    @abstractmethod
    def train_loop(self):
        pass
class ColocateRLTrainer(BaseRLTrainer):
    def train_step(self):
        # 重启推理引擎  
        self.infer_engine_controller.restart()

        # env_runnners 生成数据
        for env_runner in self.env_runners:
            trajectory = env_runner.generate_batch()
            self.replay_buffer.add(trajectory)
        self.infer_engine_controller.pause() # 包含暂停，offload

        # training
        self.training_controller.restart() # 包含onload, 准备数据
        train_batch = self.replay_buffer.get_batch()
        self.training_controller.fit(train_batch) # 开始训练
        self.training_controller.pause() # offload 

        # sync_weights
        self.sync_weights()
        self.save_ckpt()
    def train_loop(self):
        num_train_steps = 10
        for i in range(num_train_steps):
            self.train_step()
```

接着，在EnvRunner的定义中，我想将generate_batch以协程的方式，并发地启动batch_size个generate_batch的任务，帮我修改代码
```python
class EnvRunner(ABC):
    def __init__(self,
                 dataloader_cfg,
                 ):
       self.dataloader = dataloader_cfg.build()  

    def sample(self) -> dict:
        pass 

    def resume(self):
        pass
    def save(self):
        pass
    @abstractmethod
    def generate(self) -> Optional[Trajectory]:
        """
        核心方法：生成一条轨迹
        包含：取数据 -> 环境交互 -> judger -> filter -> 返回轨迹
        """
        pass

    @abstractmethod
    def generate_batch(self, batch_size: int) -> Iterator[Trajectory]:
        count = 0
        while count < batch_size:
            trajectory = self.generate()
            yield trajectory
            if trajectory is not None:
                yield trajectory
                count += 1
```

